request.query:
prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?model ?modelName ?normId ?origId WHERE {
  ?model a bboExt:Model .
  ?model bbo:name ?modelName .
  OPTIONAL { ?model tai:normalizedId ?normId . }
  OPTIONAL { ?model tai:originalId ?origId . }
  FILTER(CONTAINS(LCASE(STR(?normId)), LCASE("3c08e52742754da6a4065fc5787131dc")) || CONTAINS(LCASE(STR(?origId)), LCASE("3c08e52742754da6a4065fc5787131dc")))
}
LIMIT 10

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?choreo ?choreoName (COUNT(DISTINCT ?task) as ?taskCount) (COUNT(DISTINCT ?participant) as ?participantCount) (COUNT(DISTINCT ?flow) as ?flowCount) WHERE {
  ?choreo a bboExt:Choreography .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  OPTIONAL { ?choreo bbo:name ?choreoName . }
  OPTIONAL { ?task a bboExt:ChoreographyTask . ?task tai:belongsTo ?choreo . }
  OPTIONAL { ?participant a bboExt:Participant . ?participant tai:belongsTo ?choreo . }
  OPTIONAL { ?flow a bbo:SequenceFlow . ?flow tai:belongsTo ?choreo . }
}
GROUP BY ?choreo ?choreoName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?gateway ?gateName ?gateType ?gateDir (COUNT(DISTINCT ?incoming) as ?incomingCount) (COUNT(DISTINCT ?outgoing) as ?outgoingCount) WHERE {
  ?gateway a ?gateType .
  FILTER(?gateType IN (bboExt:ExclusiveGateway, bboExt:ParallelGateway, bboExt:EventBasedGateway))
  ?gateway tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  OPTIONAL { ?gateway bbo:name ?gateName . }
  OPTIONAL { ?gateway bboExt:gatewayDirection ?gateDir . }
  OPTIONAL { ?incoming a bbo:SequenceFlow . ?incoming bbo:has_targetRef ?gateway . }
  OPTIONAL { ?outgoing a bbo:SequenceFlow . ?outgoing bbo:has_sourceRef ?gateway . }
}
GROUP BY ?gateway ?gateName ?gateType ?gateDir
ORDER BY ?gateName

prefix bbo: <http://www.onto-bpo.eu/ontologies/bbo#>
prefix bboExt: <http://www.onto-bpo.eu/ontologies/bboExtension#>
prefix rdfs: <http://www.w3.org/2000/01/rdf-schema#>
prefix tai: <https://www.teamingai-project.eu/>
prefix xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?msgFlow ?sourceRef ?targetRef ?msgRef WHERE {
  ?msgFlow a bboExt:MessageFlow .
  ?msgFlow tai:belongsTo ?choreo .
  ?choreo tai:belongsTo ?defs .
  ?defs tai:belongsTo ?model .
  ?model tai:originalId "3c08e52742754da6a4065fc5787131dc" .
  OPTIONAL { ?msgFlow bboExt:sourceRef ?sourceRef . }
  OPTIONAL { ?msgFlow bboExt:targetRef ?targetRef . }
  OPTIONAL { ?msgFlow bboExt:messageRef ?msgRef . }
}
LIMIT 25
